mapper.update:
UPDATE auction_goods 
SET current_highest_price = #{currentHighestPrice}, bid_count = bid_count + 1 
WHERE id = #{goodsId}

mapper.select:
SELECT ar.*, u.nick_name AS buyer_name, g.goods_name AS goods_name FROM auction_record ar LEFT JOIN auction_user u ON ar.buyer_id = u.id LEFT JOIN auction_goods g ON ar.goods_id = g.id WHERE ar.del_flag = 0 AND ar.risk_rule_type = #{abnormalType}
AND ar.goods_id = #{goodsId}
AND ar.buyer_id = #{buyerId}
ORDER BY ar.bid_time DESC

SELECT ar.buyer_id AS buyerId, u.nick_name AS buyerName, COUNT(ar.id) AS bidCount FROM auction_record ar LEFT JOIN auction_user u ON ar.buyer_id = u.id WHERE ar.del_flag = 0 AND ar.risk_rule_type IN (1,2,3) AND ar.bid_time >= DATE_SUB(NOW(), INTERVAL #{windowMinutes} MINUTE)
AND ar.goods_id = #{goodsId}
GROUP BY ar.buyer_id, u.nick_name ORDER BY bidCount DESC

SELECT ar.buyer_id AS buyerId, u.nick_name AS buyerName, COUNT(ar.id) AS bidCount FROM auction_record ar LEFT JOIN auction_user u ON ar.buyer_id = u.id WHERE ar.del_flag = 0 AND ar.bid_time >= DATE_SUB(NOW(), INTERVAL #{windowMinutes} MINUTE) AND ar.bid_ip IS NOT NULL AND ar.bid_ip <> ''
AND ar.goods_id = #{goodsId}
AND ( SELECT COUNT(DISTINCT sub.buyer_id) FROM auction_record sub WHERE sub.del_flag = 0 AND sub.goods_id = ar.goods_id AND sub.bid_ip = ar.bid_ip AND sub.bid_time >= DATE_SUB(NOW(), INTERVAL #{windowMinutes} MINUTE) ) >= #{minBidCount} GROUP BY ar.buyer_id, u.nick_name ORDER BY bidCount DESC
